mapper.select:
SELECT COUNT(*) FROM observability_errors
WHERE client_platform = #{clientPlatform}
AND client_version = #{clientVersion}
AND created_at >= #{since}

SELECT error_fingerprint AS errorFingerprint, COUNT(id) AS id FROM observability_errors
WHERE error_fingerprint IS NOT NULL
GROUP BY error_fingerprint ORDER BY id DESC LIMIT #{limit}

SELECT error_fingerprint AS errorFingerprint, COUNT(id) AS id FROM observability_errors
WHERE error_fingerprint IS NOT NULL
AND created_at >= #{startDate} AND created_at < #{endDate}
GROUP BY error_fingerprint ORDER BY id DESC LIMIT #{limit}

SELECT * FROM observability_errors WHERE 1=1

    AND user_id = #{userId}


    AND client_version = #{clientVersion}


    AND error_fingerprint = #{errorFingerprint}


    AND created_at >= #{startDate}


    AND created_at < #{endDate}

ORDER BY created_at DESC
